import Foundation
import UIKit

// MARK: - AnalyticsEventType

enum AnalyticsEventType {
    case authentication(AuthEvent)
    case apiCall(APIEvent)
    case userData(UserDataEvent)
    case error(ErrorEvent)
    case custom(String, [String: Any]?)

    enum AuthEvent {
        case loginAttempt(userID: String?, email: String?, success: Bool, error: Error?)
        case logout(userID: String?)
        case refreshToken(userID: String?, success: Bool, error: Error?)
    }

    enum APIEvent {
        case request(endpoint: String, method: String, headers: [String: String]?, payload: [String: Any]?, userID: String?, token: String?)
        case response(endpoint: String, method: String, statusCode: Int, headers: [String: String]?, payload: [String: Any]?, duration: TimeInterval?, userID: String?)
        case apiError(endpoint: String, method: String, error: Error, statusCode: Int?, userID: String?)
    }

    enum UserDataEvent {
        case update(field: String, oldValue: Any?, newValue: Any?, userID: String?)
        case view(dataKey: String, value: Any?, userID: String?)
    }

    enum ErrorEvent {
        case handled(domain: String, code: Int, description: String, userInfo: [String: Any]?, userID: String?)
        case unhandledException(name: String, reason: String, callStack: [String], userID: String?)
    }
}

// MARK: - AnalyticsManager

class AnalyticsManager {

    static let shared = AnalyticsManager()

    private let dateFormatter: ISO8601DateFormatter

    private init() {
        dateFormatter = ISO8601DateFormatter()
        dateFormatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
    }

    private var currentUserID: String? {
        // Placeholder for retrieving the current user ID.
        // In a real app, this would come from your authentication manager or user session.
        return UserDefaults.standard.string(forKey: "current_user_id")
    }

    private var currentUserEmail: String? {
        // Placeholder for retrieving the current user email.
        // In a real app, this would come from your authentication manager or user session.
        return UserDefaults.standard.string(forKey: "current_user_email")
    }

    private var currentAuthToken: String? {
        // Placeholder for retrieving the current authentication token.
        // In a real app, this would come from your authentication manager or secure storage.
        return UserDefaults.standard.string(forKey: "current_user_auth_token")
    }

    func setCurrentUser(userID: String?, email: String?, token: String?) {
        UserDefaults.standard.set(userID, forKey: "current_user_id")
        UserDefaults.standard.set(email, forKey: "current_user_email")
        UserDefaults.standard.set(token, forKey: "current_user_auth_token")
        NSLog("ANALYTICS: User context set. UserID: %@, Email: %@, Token present: %@", userID ?? "N/A", email ?? "N/A", token != nil ? "YES" : "NO")
    }

    func clearCurrentUser() {
        UserDefaults.standard.removeObject(forKey: "current_user_id")
        UserDefaults.standard.removeObject(forKey: "current_user_email")
        UserDefaults.standard.removeObject(forKey: "current_user_auth_token")
        NSLog("ANALYTICS: User context cleared.")
    }

    func log(event: AnalyticsEventType) {
        let timestamp = dateFormatter.string(from: Date())
        let userID = currentUserID ?? "N/A"
        let userEmail = currentUserEmail ?? "N/A"
        let appVersion = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "N/A"
        let buildNumber = Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "N/A"
        let deviceModel = UIDevice.current.model
        let systemVersion = UIDevice.current.systemVersion

        var logString = "ANALYTICS: [\(timestamp)] [UserID: \(userID)] [Email: \(userEmail)] [AppVer: \(appVersion)-\(buildNumber)] [Device: \(deviceModel)/iOS\(systemVersion)] "

        switch event {
        case .authentication(let authEvent):
            switch authEvent {
            case .loginAttempt(let attemptedUserID, let attemptedEmail, let success, let error):
                let errorDesc = error != nil ? " - Error: \(error!.localizedDescription)" : ""
                logString += "AuthFlow - Login Attempt. UserID: \(attemptedUserID ?? "N/A"), Email: \(attemptedEmail ?? "N/A"), Success: \(success)\(errorDesc)"
            case .logout(let loggedOutUserID):
                logString += "AuthFlow - Logout. UserID: \(loggedOutUserID ?? "N/A")"
            case .refreshToken(let refreshedUserID, let success, let error):
                let errorDesc = error != nil ? " - Error: \(error!.localizedDescription)" : ""
                logString += "AuthFlow - Token Refresh. UserID: \(refreshedUserID ?? "N/A"), Success: \(success)\(errorDesc)"
            }

        case .apiCall(let apiEvent):
            switch apiEvent {
            case .request(let endpoint, let method, let headers, let payload, let reqUserID, let token):
                let currentTokenStatus = (token ?? currentAuthToken) != nil ? "YES" : "NO"
                let payloadString = payload != nil ? "\n\tPayload: \(prettyPrint(payload!))" : ""
                let headersString = headers != nil ? "\n\tHeaders: \(prettyPrint(headers!))" : ""
                logString += "API - Request. UserID: \(reqUserID ?? userID), Method: \(method), Endpoint: \(endpoint), Token Present: \(currentTokenStatus)\(headersString)\(payloadString)"
            case .response(let endpoint, let method, let statusCode, let headers, let payload, let duration, let respUserID):
                let durationString = duration != nil ? String(format: "%.3fms", duration! * 1000) : "N/A"
                let payloadString = payload != nil ? "\n\tPayload: \(prettyPrint(payload!))" : ""
                let headersString = headers != nil ? "\n\tHeaders: \(prettyPrint(headers!))" : ""
                logString += "API - Response. UserID: \(respUserID ?? userID), Method: \(method), Endpoint: \(endpoint), StatusCode: \(statusCode), Duration: \(durationString)\(headersString)\(payloadString)"
            case .apiError(let endpoint, let method, let error, let statusCode, let apiErrUserID):
                let statusCodeString = statusCode != nil ? "\(statusCode!)" : "N/A"
                logString += "API - Error. UserID: \(apiErrUserID ?? userID), Method: \(method), Endpoint: \(endpoint), StatusCode: \(statusCodeString), Error: \(error.localizedDescription) (\(error))"
            }

        case .userData(let dataEvent):
            switch dataEvent {
            case .update(let field, let oldValue, let newValue, let dataUserID):
                let oldValString = oldValue != nil ? String(describing: oldValue!) : "N/A"
                let newValString = newValue != nil ? String(describing: newValue!) : "N/A"
                logString += "UserData - Update. UserID: \(dataUserID ?? userID), Field: \(field), OldValue: \(oldValString), NewValue: \(newValString)"
            case .view(let dataKey, let value, let dataUserID):
                let valString = value != nil ? String(describing: value!) : "N/A"
                logString += "UserData - View. UserID: \(dataUserID ?? userID), DataKey: \(dataKey), Value: \(valString)"
            }

        case .error(let errorEvent):
            switch errorEvent {
            case .handled(let domain, let code, let description, let userInfo, let errUserID):
                let userInfoString = userInfo != nil ? "\n\tUserInfo: \(prettyPrint(userInfo!))" : ""
                logString += "Error - Handled. UserID: \(errUserID ?? userID), Domain: \(domain), Code: \(code), Description: \(description)\(userInfoString)"
            case .unhandledException(let name, let reason, let callStack, let errUserID):
                let callStackString = callStack.joined(separator: "\n\t\t")
                logString += "Error - Unhandled Exception. UserID: \(errUserID ?? userID), Name: \(name), Reason: \(reason)\n\tCallStack:\n\t\t\(callStackString)"
            }

        case .custom(let name, let properties):
            let propertiesString = properties != nil ? "\n\tProperties: \(prettyPrint(properties!))" : ""
            logString += "Custom Event - \(name)\(propertiesString)"
        }

        NSLog("%@", logString) // Using NSLog for its system-level logging capabilities
        print(logString)       // Using print for immediate console visibility during development
    }

    private func prettyPrint(_ dictionary: [String: Any]) -> String {
        guard let data = try? JSONSerialization.data(withJSONObject: dictionary, options: [.prettyPrinted, .sortedKeys]),
              let string = String(data: data, encoding: .utf8) else {
            return String(describing: dictionary)
        }
        return string.replacingOccurrences(of: "\n", with: "\n\t\t")
    }

    private func prettyPrint(_ dictionary: [String: String]) -> String {
        guard let data = try? JSONSerialization.data(withJSONObject: dictionary, options: [.prettyPrinted, .sortedKeys]),
              let string = String(data: data, encoding: .utf8) else {
            return String(describing: dictionary)
        }
        return string.replacingOccurrences(of: "\n", with: "\n\t\t")
    }
}

